local M = {}

-- Linear interpolation between a and b by t (0..1)
function M.lerp(a, b, t)
    return a + (b - a) * t
end

-- Clamp x between lo and hi
function M.clamp(x, lo, hi)
    return math.max(lo, math.min(hi, x))
end

-- Map x from [inLo,inHi] range to [outLo,outHi]
function M.map(x, inLo, inHi, outLo, outHi)
    return outLo + (x - inLo) / (inHi - inLo) * (outHi - outLo)
end

-- Sign of x: -1, 0, or 1
function M.sign(x)
    if x > 0 then return 1 elseif x < 0 then return -1 else return 0 end
end

-- Round to nearest integer (or decimal places)
function M.round(x, places)
    local f = 10 ^ (places or 0)
    return math.floor(x * f + 0.5) / f
end

-- Random float in [lo, hi]
function M.randomf(lo, hi)
    return lo + math.random() * (hi - lo)
end

-- Angle between two points (radians)
function M.angleTo(x1, y1, x2, y2)
    return math.atan2(y2 - y1, x2 - x1)
end

-- Distance between two points
function M.distance(x1, y1, x2, y2)
    return math.sqrt((x2-x1)^2 + (y2-y1)^2)
end

return M

