-- Define message type IDs
local MSG = {
    MOVE     = 1,
    SHOOT    = 2,
    HEALTH   = 3,
    CHAT     = 4,
    SPAWN    = 5,
}

local Messages = { types = MSG }

-- MOVE: id(uint16), x(float), y(float), vx(float), vy(float)
function Messages.encodeMOVE(id, x, y, vx, vy)
    return string.pack(">BHffff", MSG.MOVE, id, x, y, vx, vy)
end

function Messages.decodeMOVE(data)
    local _, id, x, y, vx, vy = string.unpack(">BHffff", data)
    return { id=id, x=x, y=y, vx=vx, vy=vy }
end

-- SHOOT: id(uint16), angle(float)
function Messages.encodeSHOOT(id, angle)
    return string.pack(">BHf", MSG.SHOOT, id, angle)
end

function Messages.decodeSHOOT(data)
    local _, id, angle = string.unpack(">BHf", data)
    return { id=id, angle=angle }
end

-- HEALTH: id(uint16), hp(uint8)
function Messages.encodeHEALTH(id, hp)
    return string.pack(">BHB", MSG.HEALTH, id, math.floor(hp))
end

-- CHAT: id(uint16), message(string, null-terminated)
function Messages.encodeCHAT(id, msg)
    return string.pack(">BHz", MSG.CHAT, id, msg)
end

function Messages.decodeCHAT(data)
    local _, id, msg = string.unpack(">BHz", data)
    return { id=id, msg=msg }
end

-- Dispatch: read first byte to determine type, call handler
function Messages.dispatch(data, handlers)
    local msgType = string.byte(data, 1)
    if msgType == MSG.MOVE   and handlers.onMove   then handlers.onMove(Messages.decodeMOVE(data))   end
    if msgType == MSG.SHOOT  and handlers.onShoot  then handlers.onShoot(Messages.decodeSHOOT(data)) end
    if msgType == MSG.CHAT   and handlers.onChat   then handlers.onChat(Messages.decodeCHAT(data))   end
end

return Messages

